# solution.py
"""
MultiAgentBudgetOptimizer - Collaborative budget management and optimization system.

Supports multiple users managing shared budgets with category-based limits,
expense tracking, dashboards, and collaborative optimization suggestions.
"""

import threading
import copy
import uuid
import csv
import io
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Optional, List, Dict, Callable


# ─── Sentinel ────────────────────────────────────────────────────────────────

class _UnsetType:
    """Sentinel for distinguishing 'not provided' from None."""
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __repr__(self):
        return "UNSET"

    def __bool__(self):
        return False


UNSET = _UnsetType()


# ─── Exceptions ──────────────────────────────────────────────────────────────

class NotFoundError(Exception):
    pass


class ValidationError(Exception):
    pass


class AuthorizationError(Exception):
    pass


class BudgetExceededError(Exception):
    pass


# ─── Enums ───────────────────────────────────────────────────────────────────

class ExpenseCategory(Enum):
    GROCERIES = "groceries"
    ENTERTAINMENT = "entertainment"
    UTILITIES = "utilities"
    TRANSPORT = "transport"
    HOUSING = "housing"
    HEALTHCARE = "healthcare"
    EDUCATION = "education"
    DINING = "dining"
    OTHER = "other"


class OptimizationType(Enum):
    REDUCE_SPENDING = "reduce_spending"
    REALLOCATE_FUNDS = "reallocate_funds"
    INCREASE_SAVINGS = "increase_savings"


# ─── Data Models ─────────────────────────────────────────────────────────────

class User:
    def __init__(self, user_id: int, username: str, email: str, created_at: datetime):
        self.user_id = user_id
        self.username = username
        self.email = email
        self.created_at = created_at
        self.is_active = True

    def clone(self):
        return copy.deepcopy(self)


class Expense:
    def __init__(self, expense_id: int, user_id: int, amount: float,
                 category: ExpenseCategory, description: str, created_at: datetime):
        self.expense_id = expense_id
        self.user_id = user_id
        self.amount = amount
        self.category = category
        self.description = description
        self.created_at = created_at

    def clone(self):
        return copy.deepcopy(self)


class BudgetLimit:
    def __init__(self, limit_id: int, category: ExpenseCategory, amount: float,
                 period: str, created_at: datetime, created_by: int):
        self.limit_id = limit_id
        self.category = category
        self.amount = amount
        self.period = period  # 'monthly', 'weekly', 'yearly'
        self.created_at = created_at
        self.updated_at = created_at
        self.created_by = created_by

    def clone(self):
        return copy.deepcopy(self)


class OptimizationSuggestion:
    def __init__(self, suggestion_id: int, optimization_type: OptimizationType,
                 category: ExpenseCategory, description: str,
                 potential_savings: float, created_at: datetime):
        self.suggestion_id = suggestion_id
        self.optimization_type = optimization_type
        self.category = category
        self.description = description
        self.potential_savings = potential_savings
        self.created_at = created_at
        self.applied = False

    def clone(self):
        return copy.deepcopy(self)


# ─── Shared State ────────────────────────────────────────────────────────────

class _State:
    def __init__(self, now: Callable[[], datetime] = None):
        self.lock = threading.RLock()
        self.now = now or (lambda: datetime.now(timezone.utc))
        self._id_counter = 0

        # Stores
        self.users: Dict[int, User] = {}
        self.expenses: Dict[int, Expense] = {}
        self.budget_limits: Dict[int, BudgetLimit] = {}
        self.suggestions: Dict[int, OptimizationSuggestion] = {}

        # Indexes
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.user_expenses: Dict[int, List[int]] = {}
        self.category_limits: Dict[str, int] = {}

    def next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter


# ─── User Service ────────────────────────────────────────────────────────────

class UserService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def create_user(self, username: str, email: str) -> User:
        with self._lock:
            if not username or not isinstance(username, str):
                raise ValidationError("Username must be a non-empty string")
            if not email or not isinstance(email, str):
                raise ValidationError("Email must be a non-empty string")

            username = username.strip()
            email = email.strip()

            if not username:
                raise ValidationError("Username must be a non-empty string")
            if not email or '@' not in email:
                raise ValidationError("Email must be a valid email address")

            if username.lower() in self._state.username_index:
                raise ValidationError(f"Username '{username}' already exists")
            if email.lower() in self._state.email_index:
                raise ValidationError(f"Email '{email}' already exists")

            uid = self._state.next_id()
            user = User(uid, username, email, self._state.now())
            self._state.users[uid] = user
            self._state.username_index[username.lower()] = uid
            self._state.email_index[email.lower()] = uid
            self._state.user_expenses[uid] = []
            return user.clone()

    def get_user(self, user_id: int) -> User:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            return self._state.users[user_id].clone()

    def get_user_by_username(self, username: str) -> User:
        with self._lock:
            uid = self._state.username_index.get(username.lower())
            if uid is None:
                raise NotFoundError(f"User '{username}' not found")
            return self._state.users[uid].clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [u.clone() for u in self._state.users.values() if u.is_active]

    def deactivate_user(self, user_id: int) -> User:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            self._state.users[user_id].is_active = False
            return self._state.users[user_id].clone()

    def update_user(self, user_id: int, username=UNSET, email=UNSET) -> User:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            user = self._state.users[user_id]

            if username is not UNSET:
                if not username or not isinstance(username, str):
                    raise ValidationError("Username must be a non-empty string")
                username = username.strip()
                if not username:
                    raise ValidationError("Username must be a non-empty string")
                if username.lower() != user.username.lower():
                    if username.lower() in self._state.username_index:
                        raise ValidationError(f"Username '{username}' already exists")
                    del self._state.username_index[user.username.lower()]
                    self._state.username_index[username.lower()] = user_id
                user.username = username

            if email is not UNSET:
                if not email or not isinstance(email, str):
                    raise ValidationError("Email must be a valid email address")
                email = email.strip()
                if not email or '@' not in email:
                    raise ValidationError("Email must be a valid email address")
                if email.lower() != user.email.lower():
                    if email.lower() in self._state.email_index:
                        raise ValidationError(f"Email '{email}' already exists")
                    del self._state.email_index[user.email.lower()]
                    self._state.email_index[email.lower()] = user_id
                user.email = email

            return user.clone()


# ─── Expense Service ─────────────────────────────────────────────────────────

class ExpenseService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def add_expense(self, user_id: int, amount: float, category: ExpenseCategory,
                    description: str = "") -> Expense:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            if not self._state.users[user_id].is_active:
                raise ValidationError(f"User {user_id} is deactivated")

            if not isinstance(amount, (int, float)) or isinstance(amount, bool):
                raise ValidationError("Amount must be a number")
            if amount <= 0:
                raise ValidationError("Amount must be positive")
            if not isinstance(category, ExpenseCategory):
                raise ValidationError("Invalid expense category")

            eid = self._state.next_id()
            expense = Expense(eid, user_id, float(amount), category,
                              description, self._state.now())
            self._state.expenses[eid] = expense
            self._state.user_expenses[user_id].append(eid)
            return expense.clone()

    def get_expense(self, expense_id: int) -> Expense:
        with self._lock:
            if expense_id not in self._state.expenses:
                raise NotFoundError(f"Expense {expense_id} not found")
            return self._state.expenses[expense_id].clone()

    def get_user_expenses(self, user_id: int) -> List[Expense]:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            eids = self._state.user_expenses.get(user_id, [])
            return [self._state.expenses[eid].clone() for eid in eids
                    if eid in self._state.expenses]

    def get_expenses_by_category(self, category: ExpenseCategory) -> List[Expense]:
        with self._lock:
            if not isinstance(category, ExpenseCategory):
                raise ValidationError("Invalid expense category")
            return [e.clone() for e in self._state.expenses.values()
                    if e.category == category]

    def get_total_expenses(self) -> float:
        with self._lock:
            return sum(e.amount for e in self._state.expenses.values())

    def get_user_total(self, user_id: int) -> float:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            eids = self._state.user_expenses.get(user_id, [])
            return sum(self._state.expenses[eid].amount for eid in eids
                       if eid in self._state.expenses)

    def delete_expense(self, expense_id: int, user_id: int) -> None:
        with self._lock:
            if expense_id not in self._state.expenses:
                raise NotFoundError(f"Expense {expense_id} not found")
            expense = self._state.expenses[expense_id]
            if expense.user_id != user_id:
                raise AuthorizationError("Cannot delete another user's expense")
            del self._state.expenses[expense_id]
            if expense_id in self._state.user_expenses.get(expense.user_id, []):
                self._state.user_expenses[expense.user_id].remove(expense_id)

    def update_expense(self, expense_id: int, user_id: int,
                       amount=UNSET, category=UNSET, description=UNSET) -> Expense:
        with self._lock:
            if expense_id not in self._state.expenses:
                raise NotFoundError(f"Expense {expense_id} not found")
            expense = self._state.expenses[expense_id]
            if expense.user_id != user_id:
                raise AuthorizationError("Cannot update another user's expense")

            if amount is not UNSET:
                if not isinstance(amount, (int, float)) or isinstance(amount, bool):
                    raise ValidationError("Amount must be a number")
                if amount <= 0:
                    raise ValidationError("Amount must be positive")
                expense.amount = float(amount)

            if category is not UNSET:
                if not isinstance(category, ExpenseCategory):
                    raise ValidationError("Invalid expense category")
                expense.category = category

            if description is not UNSET:
                expense.description = description

            return expense.clone()


# ─── Budget Service ──────────────────────────────────────────────────────────

class BudgetService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def set_budget_limit(self, category: ExpenseCategory, amount: float,
                         period: str = "monthly", user_id: int = None) -> BudgetLimit:
        with self._lock:
            if not isinstance(category, ExpenseCategory):
                raise ValidationError("Invalid expense category")
            if not isinstance(amount, (int, float)) or isinstance(amount, bool):
                raise ValidationError("Amount must be a number")
            if amount <= 0:
                raise ValidationError("Budget limit must be positive")
            if period not in ("monthly", "weekly", "yearly"):
                raise ValidationError("Period must be 'monthly', 'weekly', or 'yearly'")
            if user_id is not None and user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")

            key = f"{category.value}_{period}"
            if key in self._state.category_limits:
                lid = self._state.category_limits[key]
                limit = self._state.budget_limits[lid]
                limit.amount = float(amount)
                limit.updated_at = self._state.now()
                if user_id is not None:
                    limit.created_by = user_id
                return limit.clone()

            lid = self._state.next_id()
            limit = BudgetLimit(lid, category, float(amount), period,
                                self._state.now(), user_id)
            self._state.budget_limits[lid] = limit
            self._state.category_limits[key] = lid
            return limit.clone()

    def get_budget_limit(self, category: ExpenseCategory,
                         period: str = "monthly") -> Optional[BudgetLimit]:
        with self._lock:
            if not isinstance(category, ExpenseCategory):
                raise ValidationError("Invalid expense category")
            key = f"{category.value}_{period}"
            lid = self._state.category_limits.get(key)
            if lid is None:
                return None
            return self._state.budget_limits[lid].clone()

    def get_all_budget_limits(self) -> List[BudgetLimit]:
        with self._lock:
            return [bl.clone() for bl in self._state.budget_limits.values()]

    def adjust_budget_limit(self, category: ExpenseCategory, new_amount: float,
                            period: str = "monthly") -> BudgetLimit:
        with self._lock:
            if not isinstance(category, ExpenseCategory):
                raise ValidationError("Invalid expense category")
            if not isinstance(new_amount, (int, float)) or isinstance(new_amount, bool):
                raise ValidationError("Amount must be a number")
            if new_amount <= 0:
                raise ValidationError("Budget limit must be positive")

            key = f"{category.value}_{period}"
            if key not in self._state.category_limits:
                raise NotFoundError(
                    f"No budget limit for {category.value}/{period}")
            lid = self._state.category_limits[key]
            limit = self._state.budget_limits[lid]
            limit.amount = float(new_amount)
            limit.updated_at = self._state.now()
            return limit.clone()

    def delete_budget_limit(self, category: ExpenseCategory,
                            period: str = "monthly") -> None:
        with self._lock:
            key = f"{category.value}_{period}"
            if key not in self._state.category_limits:
                raise NotFoundError(
                    f"No budget limit for {category.value}/{period}")
            lid = self._state.category_limits.pop(key)
            del self._state.budget_limits[lid]

    def get_category_spending(self, category: ExpenseCategory) -> float:
        with self._lock:
            return sum(e.amount for e in self._state.expenses.values()
                       if e.category == category)

    def get_remaining_budget(self, category: ExpenseCategory,
                             period: str = "monthly") -> Optional[float]:
        with self._lock:
            key = f"{category.value}_{period}"
            lid = self._state.category_limits.get(key)
            if lid is None:
                return None
            limit = self._state.budget_limits[lid]
            spent = sum(e.amount for e in self._state.expenses.values()
                        if e.category == category)
            return limit.amount - spent

    def is_over_budget(self, category: ExpenseCategory,
                       period: str = "monthly") -> bool:
        remaining = self.get_remaining_budget(category, period)
        if remaining is None:
            return False
        return remaining < 0


# ─── Dashboard Service ───────────────────────────────────────────────────────

class DashboardService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def get_group_summary(self) -> Dict[str, Any]:
        with self._lock:
            total_expenses = sum(e.amount for e in self._state.expenses.values())
            total_budget = sum(bl.amount for bl in self._state.budget_limits.values())
            remaining = total_budget - total_expenses

            category_breakdown = {}
            for cat in ExpenseCategory:
                spent = sum(e.amount for e in self._state.expenses.values()
                            if e.category == cat)
                if spent > 0:
                    category_breakdown[cat.value] = spent

            return {
                "total_expenses": total_expenses,
                "total_budget": total_budget,
                "remaining_budget": remaining,
                "num_users": len([u for u in self._state.users.values()
                                  if u.is_active]),
                "num_expenses": len(self._state.expenses),
                "category_breakdown": category_breakdown,
            }

    def get_individual_contributions(self) -> List[Dict[str, Any]]:
        with self._lock:
            contributions = []
            total = sum(e.amount for e in self._state.expenses.values())
            for user in self._state.users.values():
                if not user.is_active:
                    continue
                eids = self._state.user_expenses.get(user.user_id, [])
                user_total = sum(self._state.expenses[eid].amount
                                 for eid in eids if eid in self._state.expenses)
                pct = (user_total / total * 100) if total > 0 else 0.0
                contributions.append({
                    "user_id": user.user_id,
                    "username": user.username,
                    "total_spent": user_total,
                    "percentage": round(pct, 2),
                    "num_expenses": len([eid for eid in eids
                                         if eid in self._state.expenses]),
                })
            contributions.sort(key=lambda x: x["total_spent"], reverse=True)
            return contributions

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError(f"User {user_id} not found")
            user = self._state.users[user_id]
            eids = self._state.user_expenses.get(user_id, [])
            expenses = [self._state.expenses[eid] for eid in eids
                        if eid in self._state.expenses]
            user_total = sum(e.amount for e in expenses)

            category_spending = {}
            for e in expenses:
                cat = e.category.value
                category_spending[cat] = category_spending.get(cat, 0) + e.amount

            over_budget_categories = []
            for cat in ExpenseCategory:
                key = f"{cat.value}_monthly"
                lid = self._state.category_limits.get(key)
                if lid is not None:
                    limit = self._state.budget_limits[lid]
                    cat_spent = sum(e.amount for e in self._state.expenses.values()
                                    if e.category == cat)
                    if cat_spent > limit.amount:
                        over_budget_categories.append(cat.value)

            return {
                "user_id": user_id,
                "username": user.username,
                "total_spent": user_total,
                "num_expenses": len(expenses),
                "category_spending": category_spending,
                "over_budget_categories": over_budget_categories,
            }

    def get_budget_status(self) -> List[Dict[str, Any]]:
        with self._lock:
            statuses = []
            for lid, limit in self._state.budget_limits.items():
                spent = sum(e.amount for e in self._state.expenses.values()
                            if e.category == limit.category)
                remaining = limit.amount - spent
                statuses.append({
                    "category": limit.category.value,
                    "period": limit.period,
                    "limit": limit.amount,
                    "spent": spent,
                    "remaining": remaining,
                    "utilization_pct": round(
                        (spent / limit.amount * 100) if limit.amount > 0 else 0, 2),
                    "over_budget": spent > limit.amount,
                })
            return statuses


# ─── Optimization Service ────────────────────────────────────────────────────

class OptimizationService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def generate_suggestions(self) -> List[OptimizationSuggestion]:
        with self._lock:
            suggestions = []

            # Analyze each category for over-spending
            for cat in ExpenseCategory:
                spent = sum(e.amount for e in self._state.expenses.values()
                            if e.category == cat)
                if spent == 0:
                    continue

                key = f"{cat.value}_monthly"
                lid = self._state.category_limits.get(key)

                if lid is not None:
                    limit = self._state.budget_limits[lid]
                    if spent > limit.amount:
                        overage = spent - limit.amount
                        sid = self._state.next_id()
                        suggestion = OptimizationSuggestion(
                            sid, OptimizationType.REDUCE_SPENDING, cat,
                            f"Reduce {cat.value} spending by ${overage:.2f} "
                            f"to stay within the ${limit.amount:.2f} budget limit.",
                            overage, self._state.now()
                        )
                        self._state.suggestions[sid] = suggestion
                        suggestions.append(suggestion.clone())
                    elif spent > limit.amount * 0.8:
                        potential = spent - (limit.amount * 0.7)
                        sid = self._state.next_id()
                        suggestion = OptimizationSuggestion(
                            sid, OptimizationType.REDUCE_SPENDING, cat,
                            f"Warning: {cat.value} spending is at "
                            f"{spent/limit.amount*100:.0f}% of budget. "
                            f"Consider reducing by ${potential:.2f}.",
                            potential, self._state.now()
                        )
                        self._state.suggestions[sid] = suggestion
                        suggestions.append(suggestion.clone())

            # Reallocation suggestions
            under_budget = []
            over_budget = []
            for lid, limit in self._state.budget_limits.items():
                spent = sum(e.amount for e in self._state.expenses.values()
                            if e.category == limit.category)
                if spent < limit.amount * 0.5:
                    under_budget.append((limit.category, limit.amount - spent))
                elif spent > limit.amount:
                    over_budget.append((limit.category, spent - limit.amount))

            for over_cat, over_amt in over_budget:
                for under_cat, under_amt in under_budget:
                    realloc = min(over_amt, under_amt)
                    if realloc > 0:
                        sid = self._state.next_id()
                        suggestion = OptimizationSuggestion(
                            sid, OptimizationType.REALLOCATE_FUNDS, over_cat,
                            f"Reallocate ${realloc:.2f} from {under_cat.value} "
                            f"budget to {over_cat.value} to cover overspending.",
                            realloc, self._state.now()
                        )
                        self._state.suggestions[sid] = suggestion
                        suggestions.append(suggestion.clone())
                        break

            # Savings suggestions for highest spenders
            if self._state.expenses:
                user_totals = {}
                for e in self._state.expenses.values():
                    user_totals[e.user_id] = user_totals.get(e.user_id, 0) + e.amount

                if user_totals:
                    avg_spending = sum(user_totals.values()) / len(user_totals)
                    for uid, total in user_totals.items():
                        if total > avg_spending * 1.5 and uid in self._state.users:
                            savings = total - avg_spending
                            sid = self._state.next_id()
                            user = self._state.users[uid]
                            suggestion = OptimizationSuggestion(
                                sid, OptimizationType.INCREASE_SAVINGS, 
                                ExpenseCategory.OTHER,
                                f"User '{user.username}' spends "
                                f"${total - avg_spending:.2f} above average. "
                                f"Potential savings: ${savings:.2f}.",
                                savings, self._state.now()
                            )
                            self._state.suggestions[sid] = suggestion
                            suggestions.append(suggestion.clone())

            return suggestions

    def get_suggestions(self) -> List[OptimizationSuggestion]:
        with self._lock:
            return [s.clone() for s in self._state.suggestions.values()]

    def apply_suggestion(self, suggestion_id: int) -> OptimizationSuggestion:
        with self._lock:
            if suggestion_id not in self._state.suggestions:
                raise NotFoundError(f"Suggestion {suggestion_id} not found")
            s = self._state.suggestions[suggestion_id]
            s.applied = True
            return s.clone()

    def get_optimization_report(self) -> Dict[str, Any]:
        with self._lock:
            all_suggestions = list(self._state.suggestions.values())
            total_potential = sum(s.potential_savings for s in all_suggestions)
            applied = [s for s in all_suggestions if s.applied]
            realized = sum(s.potential_savings for s in applied)

            by_type = {}
            for s in all_suggestions:
                t = s.optimization_type.value
                by_type[t] = by_type.get(t, 0) + 1

            return {
                "total_suggestions": len(all_suggestions),
                "applied_suggestions": len(applied),
                "total_potential_savings": total_potential,
                "realized_savings": realized,
                "suggestions_by_type": by_type,
            }


# ─── Main Optimizer (Facade) ─────────────────────────────────────────────────

class MultiAgentBudgetOptimizer:
    """
    Main facade for the collaborative budget optimization system.
    Thread-safe, supports multiple users with shared budget management.
    """

    def __init__(self, now: Callable[[], datetime] = None):
        self._state = _State(now=now)
        self._lock = self._state.lock

        self.users = UserService(self._state)
        self.expenses = ExpenseService(self._state)
        self.budgets = BudgetService(self._state)
        self.dashboard = DashboardService(self._state)
        self.optimization = OptimizationService(self._state)

    @property
    def lock(self):
        return self._lock

    def export_summary_csv(self) -> str:
        """Export the group financial summary as CSV."""
        with self._lock:
            summary = self.dashboard.get_group_summary()
            contributions = self.dashboard.get_individual_contributions()

            output = io.StringIO()
            writer = csv.writer(output)

            writer.writerow(["Group Financial Summary"])
            writer.writerow(["Total Expenses", summary["total_expenses"]])
            writer.writerow(["Total Budget", summary["total_budget"]])
            writer.writerow(["Remaining Budget", summary["remaining_budget"]])
            writer.writerow(["Number of Users", summary["num_users"]])
            writer.writerow([])

            writer.writerow(["Individual Contributions"])
            writer.writerow(["Username", "Total Spent", "Percentage",
                             "Num Expenses"])
            for c in contributions:
                writer.writerow([c["username"], c["total_spent"],
                                 c["percentage"], c["num_expenses"]])

            writer.writerow([])
            writer.writerow(["Category Breakdown"])
            writer.writerow(["Category", "Amount"])
            for cat, amt in summary["category_breakdown"].items():
                writer.writerow([cat, amt])

            return output.getvalue()


