class TestConcurrency(unittest.TestCase):
    def test_shared_lock_identity(self):
        optimizer = MultiAgentBudgetOptimizer()
        self.assertIs(optimizer.users._lock, optimizer.expenses._lock)
        self.assertIs(optimizer.expenses._lock, optimizer.budgets._lock)
        self.assertIs(optimizer.budgets._lock, optimizer.dashboard._lock)
        self.assertIs(optimizer.dashboard._lock, optimizer.optimization._lock)

    def test_concurrent_user_creation(self):
        optimizer = MultiAgentBudgetOptimizer()
        results = []
        errors = []

        def create_user(i):
            try:
                user = optimizer.users.create_user(
                    f"user{i}", f"user{i}@example.com")
                results.append(user.user_id)
            except Exception as e:
                errors.append(e)

        threads = [threading.Thread(target=create_user, args=(i,))
                   for i in range(50)]
        for t in threads:
            t.start()
        for t in threads:
