class TestIntegration(unittest.TestCase):
    """End-to-end integration tests."""

    def test_full_workflow(self):
        optimizer = MultiAgentBudgetOptimizer()

        # Create users
        alice = optimizer.users.create_user("alice", "alice@example.com")
        bob = optimizer.users.create_user("bob", "bob@example.com")

        # Set budgets
        optimizer.budgets.set_budget_limit(ExpenseCategory.GROCERIES, 300)
        optimizer.budgets.set_budget_limit(ExpenseCategory.ENTERTAINMENT, 200)
        optimizer.budgets.set_budget_limit(ExpenseCategory.UTILITIES, 150)

        # Add expenses
        optimizer.expenses.add_expense(
            alice.user_id, 200, ExpenseCategory.GROCERIES, "Weekly shop")
        optimizer.expenses.add_expense(
            alice.user_id, 80, ExpenseCategory.ENTERTAINMENT, "Movies")
        optimizer.expenses.add_expense(
            bob.user_id, 150, ExpenseCategory.GROCERIES, "Bulk buy")
        optimizer.expenses.add_expense(
            bob.user_id, 100, ExpenseCategory.UTILITIES, "Electric bill")

        # Check dashboard
        summary = optimizer.dashboard.get_group_summary()
        self.assertEqual(summary["total_expenses"], 530.0)
        self.assertEqual(summary["total_budget"], 650.0)
        self.assertEqual(summary["remaining_budget"], 120.0)

        # Check individual
        contributions = optimizer.dashboard.get_individual_contributions()
        self.assertEqual(len(contributions), 2)

        # Check over-budget (groceries: 350 > 300)
        self.assertTrue(
            optimizer.budgets.is_over_budget(ExpenseCategory.GROCERIES))
        self.assertFalse(
            optimizer.budgets.is_over_budget(ExpenseCategory.ENTERTAINMENT))

        # Generate optimization suggestions
        suggestions = optimizer.optimization.generate_suggestions()
        self.assertTrue(len(suggestions) > 0)

        # Apply a suggestion
        optimizer.optimization.apply_suggestion(suggestions[0].suggestion_id)
        report = optimizer.optimization.get_optimization_report()
        self.assertEqual(report["applied_suggestions"], 1)

        # Export CSV
        csv_output = optimizer.export_summary_csv()
        self.assertIn("alice", csv_output)
        self.assertIn("bob", csv_output)

    def test_budget_adjustment_workflow(self):
        optimizer = MultiAgentBudgetOptimizer()
        alice = optimizer.users.create_user("alice", "alice@example.com")

        # Set initial budget
        optimizer.budgets.set_budget_limit(ExpenseCategory.GROCERIES, 200)

        # Spend within limit
        optimizer.expenses.add_expense(
            alice.user_id, 180, ExpenseCategory.GROCERIES)
        self.assertFalse(
            optimizer.budgets.is_over_budget(ExpenseCategory.GROCERIES))

        # Add more expenses to exceed
        optimizer.expenses.add_expense(
            alice.user_id, 50, ExpenseCategory.GROCERIES)
        self.assertTrue(
            optimizer.budgets.is_over_budget(ExpenseCategory.GROCERIES))

        # Adjust budget up
        optimizer.budgets.adjust_budget_limit(ExpenseCategory.GROCERIES, 300)
        self.assertFalse(
            optimizer.budgets.is_over_budget(ExpenseCategory.GROCERIES))
        self.assertEqual(
            optimizer.budgets.get_remaining_budget(ExpenseCategory.GROCERIES), 70.0)


